import React from "react";

function DashboardHome() {

  return (
    <div>
      <h1>Market Dashboard</h1>

      <div className="cards">

        <div className="card">Total Profit : ₹24,000</div>
        <div className="card">Total Loss : ₹6,500</div>
        <div className="card">Expenses : ₹12,000</div>
        <div className="card">Inflation Loss : ₹3,200</div>

      </div>

    </div>
  );
}

export default DashboardHome;
